html:
{%- macro add_header(page_num, max_pages, doc, letter_head, no_letterhead, footer, print_settings=None, print_heading_template=None) -%}
	{% if letter_head and not no_letterhead %}
		<div class="letter-head">{{ letter_head }}</div>
	{% endif %}
	{% if print_heading_template %}
		{{ frappe.render_template(print_heading_template, {"doc":doc}) }}
	{% endif %}
{%- endmacro -%}

{% for page in layout %}
<div class="page-break tally-invoice">
	<div {% if print_settings.repeat_header_footer %} id="header-html" class="hidden-pdf" {% endif %}>
		{{ add_header(loop.index, layout|len, doc, letter_head, no_letterhead, footer, print_settings) }}
	</div>
	{%- if doc.meta.is_submittable and doc.docstatus==2-%}
		<div class="text-center" document-status="cancelled">
			<h4 style="margin-top: 20px;">{{ _("CANCELLED") }}</h4>
		</div>
	{%- endif -%}
	{%- if doc.meta.is_submittable and doc.docstatus==0 and (print_settings==None or print_settings.add_draft_heading) -%}
		<div class="text-center" document-status="draft">
			<h4 style="margin-top: 20px !important;">{{ _("DRAFT") }}</h4>
		</div>
	{%- endif -%}

	<style>
		/* ── Tally-style Purchase Invoice ── */
		@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap');

		.tally-invoice {
			font-family: 'Inter', 'Segoe UI', sans-serif;
			color: #1a1a1a;
			font-size: 11px;
			line-height: 1.5;
			padding: 0;
		}

		.tally-invoice .print-format {
			padding: 0 !important;
			margin: 0 !important;
		}

		/* Outer border */
		.tally-border {
			border: 2px solid #222;
			padding: 0;
		}

		/* ── Company Header ── */
		.tally-company-header {
			text-align: center;
			padding: 12px 15px 8px;
			border-bottom: 2px solid #222;
			background: #f9f9f9;
		}
		.tally-company-header .company-name {
			font-size: 18px;
			font-weight: 700;
			color: #111;
			letter-spacing: 0.5px;
			text-transform: uppercase;
		}
		.tally-company-header .company-detail {
			font-size: 10px;
			color: #555;
			margin-top: 2px;
		}
		.tally-company-header .gstin-label {
			font-size: 11px;
			font-weight: 600;
			color: #333;
			margin-top: 4px;
		}

		/* ── Voucher Title ── */
		.tally-voucher-title {
			text-align: center;
			padding: 6px 0;
			border-bottom: 1px solid #222;
			background: #fff;
		}
		.tally-voucher-title h3 {
			margin: 0;
			font-size: 14px;
			font-weight: 700;
			letter-spacing: 1px;
			text-transform: uppercase;
			color: #111;
		}

		/* ── Info rows ── */
		.tally-info-row {
			display: table;
			width: 100%;
			border-bottom: 1px solid #bbb;
		}
		.tally-info-cell {
			display: table-cell;
			padding: 6px 10px;
			vertical-align: top;
		}
		.tally-info-cell.left {
			width: 50%;
			border-right: 1px solid #bbb;
		}
		.tally-info-cell.right {
			width: 50%;
		}
		.tally-info-cell .label {
			font-weight: 600;
			color: #444;
			font-size: 10px;
			text-transform: uppercase;
			letter-spacing: 0.3px;
		}
		.tally-info-cell .value {
			font-size: 11px;
			color: #111;
			margin-top: 1px;
		}

		/* ── Items table ── */
		table.tally-items {
			width: 100%;
			border-collapse: collapse;
			border-bottom: 2px solid #222;
		}
		table.tally-items thead th {
			background: #f0f0f0;
			padding: 6px 8px;
			font-weight: 600;
			font-size: 10px;
			text-transform: uppercase;
			color: #333;
			border-bottom: 2px solid #222;
			border-right: 1px solid #bbb;
			letter-spacing: 0.3px;
		}
		table.tally-items thead th:last-child {
			border-right: none;
		}
		table.tally-items tbody td {
			padding: 5px 8px;
			border-bottom: 1px solid #ddd;
			border-right: 1px solid #ddd;
			font-size: 11px;
			vertical-align: top;
		}
		table.tally-items tbody td:last-child {
			border-right: none;
		}
		table.tally-items tbody tr:last-child td {
			border-bottom: none;
		}
		table.tally-items .item-desc {
			font-size: 9px;
			color: #666;
			margin-top: 2px;
		}
		table.tally-items .col-sr    { width: 5%; text-align: center; }
		table.tally-items .col-item  { width: 30%; }
		table.tally-items .col-hsn   { width: 12%; text-align: center; }
		table.tally-items .col-qty   { width: 10%; text-align: right; }
		table.tally-items .col-uom   { width: 8%; text-align: center; }
		table.tally-items .col-rate  { width: 15%; text-align: right; }
		table.tally-items .col-amt   { width: 20%; text-align: right; }

		/* ── Tax & totals ── */
		.tally-summary {
			display: table;
			width: 100%;
		}
		.tally-summary .left-col {
			display: table-cell;
			width: 55%;
			vertical-align: top;
			border-right: 1px solid #bbb;
			padding: 0;
		}
		.tally-summary .right-col {
			display: table-cell;
			width: 45%;
			vertical-align: top;
			padding: 0;
		}

		/* Tax table */
		table.tally-tax {
			width: 100%;
			border-collapse: collapse;
		}
		table.tally-tax td {
			padding: 4px 10px;
			font-size: 11px;
			border-bottom: 1px solid #ddd;
		}
		table.tally-tax tr:last-child td {
			border-bottom: none;
		}
		table.tally-tax .tax-label {
			color: #555;
		}
		table.tally-tax .tax-value {
			text-align: right;
			color: #111;
			font-weight: 500;
		}

		/* Totals */
		table.tally-totals {
			width: 100%;
			border-collapse: collapse;
		}
		table.tally-totals td {
			padding: 4px 10px;
			font-size: 11px;
			border-bottom: 1px solid #ddd;
		}
		table.tally-totals tr:last-child td {
			border-bottom: none;
		}
		table.tally-totals .total-label {
			text-align: right;
			color: #555;
			width: 60%;
		}
		table.tally-totals .total-value {
			text-align: right;
			color: #111;
			font-weight: 500;
			width: 40%;
		}
		table.tally-totals .grand-row td {
			font-weight: 700;
			font-size: 13px;
			color: #111;
			border-top: 2px solid #222;
			border-bottom: 2px solid #222;
			padding: 7px 10px;
		}

		/* ── Amount in words ── */
		.tally-words {
			padding: 8px 10px;
			border-top: 1px solid #bbb;
			border-bottom: 1px solid #bbb;
			font-size: 11px;
			background: #fafafa;
		}
		.tally-words .words-label {
			font-weight: 600;
			color: #333;
			text-transform: uppercase;
			font-size: 10px;
		}
		.tally-words .words-value {
			color: #111;
			font-weight: 500;
		}

		/* ── Footer / Signatory ── */
		.tally-footer {
			display: table;
			width: 100%;
			min-height: 80px;
		}
		.tally-footer .left-foot {
			display: table-cell;
			width: 55%;
			vertical-align: bottom;
			padding: 8px 10px;
			border-right: 1px solid #bbb;
		}
		.tally-footer .right-foot {
			display: table-cell;
			width: 45%;
			vertical-align: bottom;
			padding: 8px 10px;
			text-align: right;
		}
		.tally-footer .sig-line {
			text-align: right;
			font-weight: 600;
			font-size: 11px;
			color: #333;
		}
		.tally-footer .company-for {
			text-align: right;
			font-size: 10px;
			color: #666;
			margin-bottom: 30px;
		}
		.computer-gen {
			text-align: center;
			font-size: 9px;
			color: #999;
			padding: 4px 0;
			border-top: 1px solid #bbb;
		}

		/* Utilities */
		.text-center { text-align: center; }
		.text-right  { text-align: right; }
		.text-left   { text-align: left; }
	</style>

	<div class="tally-border">
		<!-- ── Company Header ── -->
		<div class="tally-company-header">
			<div class="company-name">{{ doc.company }}</div>
			{% if doc.company_address_display %}
				<div class="company-detail">{{ doc.company_address_display | striptags | replace('\n', ', ') }}</div>
			{% else %}
				{% set comp = frappe.get_doc('Company', doc.company) %}
				{% if comp.get('address_html') %}
					<div class="company-detail">{{ comp.address_html | striptags | replace('\n', ', ') }}</div>
				{% endif %}
			{% endif %}
			{% set company_gstin = doc.company_gstin or frappe.db.get_value('Company', doc.company, 'gstin') %}
			{% if company_gstin %}
				<div class="gstin-label">GSTIN: {{ company_gstin }}</div>
			{% endif %}
		</div>

		<!-- ── Voucher Title ── -->
		<div class="tally-voucher-title">
			<h3>{{ _("Purchase Invoice") }}</h3>
		</div>

		<!-- ── Invoice Info ── -->
		<div class="tally-info-row">
			<div class="tally-info-cell left">
				<div class="label">{{ _("Invoice No.") }}</div>
				<div class="value">{{ doc.name }}</div>
			</div>
			<div class="tally-info-cell right">
				<div class="label">{{ _("Date") }}</div>
				<div class="value">{{ frappe.utils.format_date(doc.posting_date) }}</div>
			</div>
		</div>

		{% if doc.bill_no or doc.bill_date %}
		<div class="tally-info-row">
			<div class="tally-info-cell left">
				<div class="label">{{ _("Supplier Invoice No.") }}</div>
				<div class="value">{{ doc.bill_no or "-" }}</div>
			</div>
			<div class="tally-info-cell right">
				<div class="label">{{ _("Supplier Invoice Date") }}</div>
				<div class="value">{{ frappe.utils.format_date(doc.bill_date) if doc.bill_date else "-" }}</div>
			</div>
		</div>
		{% endif %}

		<!-- ── Supplier & Shipping ── -->
		<div class="tally-info-row">
			<div class="tally-info-cell left">
				<div class="label">{{ _("Supplier Details") }}</div>
				<div class="value">
					<strong>{{ doc.supplier_name }}</strong><br>
					{% if doc.address_display %}
						{{ doc.address_display }}
					{% endif %}
					{% if doc.supplier_gstin %}
						<br><strong>GSTIN:</strong> {{ doc.supplier_gstin }}
					{% endif %}
				</div>
			</div>
			<div class="tally-info-cell right">
				<div class="label">{{ _("Shipping Address") }}</div>
				<div class="value">
					{% if doc.shipping_address_display %}
						{{ doc.shipping_address_display }}
					{% elif doc.billing_address_display %}
						{{ doc.billing_address_display }}
					{% else %}
						{{ doc.company }}
					{% endif %}
				</div>
			</div>
		</div>

		{% if doc.due_date %}
		<div class="tally-info-row">
			<div class="tally-info-cell left">
				<div class="label">{{ _("Due Date") }}</div>
				<div class="value">{{ frappe.utils.format_date(doc.due_date) }}</div>
			</div>
			<div class="tally-info-cell right">
				{% if doc.payment_terms_template %}
					<div class="label">{{ _("Payment Terms") }}</div>
					<div class="value">{{ doc.payment_terms_template }}</div>
				{% endif %}
			</div>
		</div>
		{% endif %}

		<!-- ── Items Table ── -->
		<table class="tally-items">
			<thead>
				<tr>
					<th class="col-sr">{{ _("Sr") }}</th>
					<th class="col-item">{{ _("Particulars") }}</th>
					<th class="col-hsn">{{ _("HSN/SAC") }}</th>
					<th class="col-qty">{{ _("Qty") }}</th>
					<th class="col-uom">{{ _("UOM") }}</th>
					<th class="col-rate">{{ _("Rate") }}</th>
					<th class="col-amt">{{ _("Amount") }}</th>
				</tr>
			</thead>
			<tbody>
				{% for item in doc.items %}
				<tr>
					<td class="col-sr">{{ item.idx }}</td>
					<td class="col-item">
						<strong>{{ item.item_name }}</strong>
						{% if item.item_code and item.item_code != item.item_name %}
							<div class="item-desc">{{ item.item_code }}</div>
						{% endif %}
						{% if item.description and item.description != item.item_name %}
							<div class="item-desc">{{ item.description | truncate(80) | striptags }}</div>
						{% endif %}
					</td>
					<td class="col-hsn">{{ item.gst_hsn_code or "" }}</td>
					<td class="col-qty">{{ item.qty }}</td>
					<td class="col-uom">{{ item.uom or "" }}</td>
					<td class="col-rate">{{ item.get_formatted("rate", doc) }}</td>
					<td class="col-amt">{{ item.get_formatted("amount", doc) }}</td>
				</tr>
				{% endfor %}
			</tbody>
		</table>

		<!-- ── Tax + Totals Summary ── -->
		<div class="tally-summary">
			<div class="left-col">
				{% if doc.taxes %}
				<table class="tally-tax">
					<tr>
						<td colspan="2" style="font-weight:600; font-size:10px; text-transform:uppercase; color:#444; border-bottom:1px solid #bbb; padding:6px 10px;">
							{{ _("Tax Breakup") }}
						</td>
					</tr>
					{%- for tax in doc.taxes -%}
						{%- if tax.tax_amount or (print_settings and print_settings.print_taxes_with_zero_amount) -%}
						<tr>
							<td class="tax-label">{{ tax.description }} @ {{ tax.rate }}%</td>
							<td class="tax-value">{{ tax.get_formatted("tax_amount") }}</td>
						</tr>
						{%- endif -%}
					{%- endfor -%}
				</table>
				{% endif %}
			</div>
			<div class="right-col">
				<table class="tally-totals">
					<tr>
						<td class="total-label">{{ _("Net Total") }}</td>
						<td class="total-value">{{ doc.get_formatted("net_total", doc) }}</td>
					</tr>
					{%- if doc.discount_amount -%}
					<tr>
						<td class="total-label">{{ _("Discount") }}</td>
						<td class="total-value">- {{ doc.get_formatted("discount_amount", doc) }}</td>
					</tr>
					{%- endif -%}
					{%- if doc.total_taxes_and_charges -%}
					<tr>
						<td class="total-label">{{ _("Total Tax") }}</td>
						<td class="total-value">{{ doc.get_formatted("total_taxes_and_charges", doc) }}</td>
					</tr>
					{%- endif -%}
					<tr class="grand-row">
						<td class="total-label">{{ _("Grand Total") }}</td>
						<td class="total-value">{{ doc.get_formatted("grand_total", doc) }}</td>
					</tr>
					{%- if doc.rounded_total -%}
					<tr>
						<td class="total-label">{{ _("Rounded Total") }}</td>
						<td class="total-value" style="font-weight:600;">{{ doc.get_formatted("rounded_total", doc) }}</td>
					</tr>
					{%- endif -%}
				</table>
			</div>
		</div>

		<!-- ── Amount in Words ── -->
		{% if doc.in_words %}
		<div class="tally-words">
			<span class="words-label">{{ _("Amount Chargeable (in words)") }}:</span>
			<span class="words-value">{{ doc.in_words }}</span>
		</div>
		{% endif %}

		<!-- ── Terms ── -->
		{% if doc.terms %}
		<div style="padding: 6px 10px; font-size: 10px; color: #555; border-bottom: 1px solid #bbb;">
			<div style="font-weight:600; text-transform: uppercase; font-size: 10px; color: #444; margin-bottom: 3px;">{{ _("Terms & Conditions") }}</div>
			{{ doc.terms }}
		</div>
		{% endif %}

		<!-- ── Footer: Remarks + Signatory ── -->
		<div class="tally-footer">
			<div class="left-foot">
				{% if doc.remarks %}
					<div style="font-size:10px; color:#666;">
						<strong>{{ _("Remarks") }}:</strong> {{ doc.remarks }}
					</div>
				{% endif %}
			</div>
			<div class="right-foot">
				<div class="company-for">{{ _("For") }} {{ doc.company }}</div>
				<div class="sig-line">{{ _("Authorised Signatory") }}</div>
			</div>
		</div>

		<!-- ── Computer Generated ── -->
		<div class="computer-gen">
			{{ _("This is a Computer Generated Invoice") }}
		</div>
	</div>
</div>
{% endfor %}
